#[naked]
#[no_mangle]
#[link_section = ".text.entry"]
unsafe extern "C" fn _start() -> ! {
    asm!(
        "
            la      sp, {boot_stack}
            li      t0, {stack_size}
            add     sp, sp, t0

            la      t0, {page_table}
            srli    t0, t0, 12
            li      t1, 8
            slli    t1, t1, 60
            or      t0, t0, t1
            csrw    satp, t0
            sfence.vma
            fence.i

            li      s0, {virt_addr_start}
            or      sp, sp, s0

            la      a2, {entry}
            or      a2, a2, s0
            jr      a2
        ",
        stack_size = const crate::STACK_SIZE,
        boot_stack = sym crate::BOOT_STACK,
        page_table = sym BOOT_PAGE_TABLE,
        entry = sym super::rust_temp_main,
        virt_addr_start = const VIRT_ADDR_START,
        options(noreturn)
    )
}

pub fn switch_to_kernel_page_table() {
    unsafe {
        riscv::register::satp::set(
            riscv::register::satp::Mode::Sv39,
            0,
            (core::ptr::addr_of!(BOOT_PAGE_TABLE) as usize & !VIRT_ADDR_START) >> 12,
        );
        sfence_vma_all();
    }
}

pub fn kernel_page_table() -> PageTable {
    PageTable(PhysAddr(unsafe {
        core::ptr::addr_of!(BOOT_PAGE_TABLE) as usize & !VIRT_ADDR_START
    }))
}

use core::{
