};

use riscv::register::sstatus::{self, Sstatus};

use crate::TrapFrameArgs;

#[repr(C)]
#[derive(Clone)]
pub struct TrapFrame {
    pub x: [usize; 32],
    pub sstatus: Sstatus,
    pub sepc: usize,
    pub fsx: [usize; 2],
}

impl Debug for TrapFrame {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
        f.debug_struct("TrapFrame")
            .field("ra", &self.x[1])
            .field("sp", &self.x[2])
            .field("gp", &self.x[3])
            .field("tp", &self.x[4])
            .field("a0", &self.x[10])
            .field("a1", &self.x[11])
            .field("a2", &self.x[12])
            .field("a3", &self.x[13])
            .field("a4", &self.x[14])
            .field("a5", &self.x[15])
            .field("a6", &self.x[16])
            .field("a7", &self.x[17])
            .field("sstatus", &self.sstatus)
            .field("sepc", &self.sepc)
            .finish()
    }
}

impl TrapFrame {
    #[inline]
    pub fn new() -> Self {
        Self {
            x: [0; 32],
            sstatus: sstatus::read(),
            sepc: 0,
            fsx: [0; 2],
        }
    }

    #[inline]
    pub fn args(&self) -> [usize; 6] {
        self.x[10..16].try_into().expect("trap args length")
    }

    #[inline]
    pub fn syscall_ok(&mut self) {
        self.sepc += 4;
    }
}

impl Index<TrapFrameArgs> for TrapFrame {
    type Output = usize;

    fn index(&self, index: TrapFrameArgs) -> &Self::Output {
        match index {
            TrapFrameArgs::SEPC => &self.sepc,
            TrapFrameArgs::RA => &self.x[1],
            TrapFrameArgs::SP => &self.x[2],
            TrapFrameArgs::RET => &self.x[10],
            TrapFrameArgs::ARG0 => &self.x[10],
            TrapFrameArgs::ARG1 => &self.x[11],
            TrapFrameArgs::ARG2 => &self.x[12],
            TrapFrameArgs::TLS => &self.x[4],
            TrapFrameArgs::SYSCALL => &self.x[17],
        }
    }
}

impl IndexMut<TrapFrameArgs> for TrapFrame {
    fn index_mut(&mut self, index: TrapFrameArgs) -> &mut Self::Output {
        match index {
            TrapFrameArgs::SEPC => &mut self.sepc,
            TrapFrameArgs::RA => &mut self.x[1],
            TrapFrameArgs::SP => &mut self.x[2],
            TrapFrameArgs::RET => &mut self.x[10],
            TrapFrameArgs::ARG0 => &mut self.x[10],
            TrapFrameArgs::ARG1 => &mut self.x[11],
            TrapFrameArgs::ARG2 => &mut self.x[12],
            TrapFrameArgs::TLS => &mut self.x[4],
            TrapFrameArgs::SYSCALL => &mut self.x[17],
        }
    }
}

use core::arch::{asm, global_asm};

use riscv::register::{
    scause::{self, Exception, Interrupt, Trap},
    sie, sstatus, stval,
};

use crate::{add_irq, TrapFrame, TrapType, VIRT_ADDR_START};

use super::timer;

global_asm!(
    r"
    .altmacro
    .macro LOAD reg, offset
        ld  \reg, \offset*8(sp)
    .endm

    .macro SAVE reg, offset
        sd  \reg, \offset*8(sp)
    .endm

    .macro LOAD_N n
        ld  x\n, \n*8(sp)
    .endm

    .macro SAVE_N n
        sd  x\n, \n*8(sp)
    .endm

    .macro SAVE_GENERAL_REGS
        SAVE    x1, 1
        csrr    x1, sscratch
        SAVE    x1, 2
        .set    n, 3
        .rept   29
            SAVE_N  %n
        .set    n, n + 1
        .endr

        csrr    t0, sstatus
        csrr    t1, sepc
        SAVE    t0, 32
        SAVE    t1, 33
    .endm

    .macro LOAD_GENERAL_REGS
        LOAD    t0, 32
        LOAD    t1, 33
        csrw    sstatus, t0
        csrw    sepc, t1

        LOAD    x1, 1
        .set    n, 3
        .rept   29
            LOAD_N  %n
        .set    n, n + 1
        .endr
        LOAD    x2, 2
    .endm
"
);

pub fn init_interrupt() {
    super::sigtrx::init();
    unsafe {
        // Allow S-mode (kernel) to access U-mode pages directly. The syscall
        // layer reads/writes user buffers in place (e.g. user_translated_bytes
        // returns slices pointing at user VAs), which faults without SUM.
        // Unlike LoongArch, RISC-V gates supervisor access to user pages on
        // this bit. SUM is not cleared by traps, so setting it once suffices.
        sstatus::set_sum();
        asm!("csrw stvec, a0", in("a0") kernelvec as usize);
    }
    timer::init();
}

#[no_mangle]
fn kernel_callback(context: &mut TrapFrame) -> TrapType {
    let scause = scause::read();
    let stval = stval::read();
    let trap_type = match scause.cause() {
        Trap::Exception(Exception::Breakpoint) => {
            context.sepc += 4;
            TrapType::Breakpoint
        }
        Trap::Exception(Exception::LoadFault) => {
            if stval > VIRT_ADDR_START {
                panic!("kernel load fault: {:#x}", stval);
            }
            TrapType::Unknown
        }
        Trap::Exception(Exception::UserEnvCall) => TrapType::UserEnvCall,
        Trap::Interrupt(Interrupt::SupervisorTimer) => {
            timer::set_next_timeout();
            add_irq(5);
            TrapType::Time
        }
        Trap::Exception(Exception::StorePageFault) => TrapType::StorePageFault(stval),
        Trap::Exception(Exception::StoreFault) => TrapType::StorePageFault(stval),
        Trap::Exception(Exception::InstructionPageFault) => TrapType::InstructionPageFault(stval),
        Trap::Exception(Exception::IllegalInstruction) => TrapType::IllegalInstruction(stval),
        Trap::Exception(Exception::LoadPageFault) => TrapType::LoadPageFault(stval),
        Trap::Interrupt(Interrupt::SupervisorExternal) => TrapType::SupervisorExternal,
        _ => {
            error!(
                "riscv trap: {:?} stval={:#x} sepc={:#x}",
                scause.cause(),
                stval,
                context.sepc
            );
            panic!("unknown trap: {:#x?}", context);
        }
    };
    crate::api::ArchInterface::kernel_interrupt(context, trap_type);
    trap_type
}

#[naked]
pub unsafe extern "C" fn kernelvec() {
    asm!(
        "
            .align 4
            .altmacro

            csrrw   sp, sscratch, sp
            bnez    sp, uservec
            csrr    sp, sscratch

            addi    sp, sp, -{cx_size}
            SAVE_GENERAL_REGS
            csrw    sscratch, x0

            mv      a0, sp
            call    kernel_callback

            LOAD_GENERAL_REGS
            sret
        ",
        cx_size = const crate::consts::TRAPFRAME_SIZE,
        options(noreturn)
    )
}

#[naked]
#[no_mangle]
extern "C" fn user_restore(_context: *mut TrapFrame) {
    unsafe {
        asm!(
            "
                .align 4
                .altmacro
                addi    sp, sp, -18*8
                sd      sp, 8*1(sp)
                sd      gp, 8*2(sp)
                sd      tp, 8*3(sp)
                sd      s0, 8*4(sp)
                sd      s1, 8*5(sp)
                sd      s2, 8*6(sp)
                sd      s3, 8*7(sp)
                sd      s4, 8*8(sp)
                sd      s5, 8*9(sp)
                sd      s6, 8*10(sp)
                sd      s7, 8*11(sp)
                sd      s8, 8*12(sp)
                sd      s9, 8*13(sp)
                sd      s10, 8*14(sp)
                sd      s11, 8*15(sp)
                sd      a0, 8*16(sp)
                sd      ra, 8*17(sp)

                sd      sp, 8*0(a0)
                csrw    sscratch, a0
                mv      sp, a0

                .short  0x2452
                .short  0x24f2

                LOAD_GENERAL_REGS
                sret
            ",
            options(noreturn)
        )
    }
}

#[naked]
#[no_mangle]
#[allow(named_asm_labels)]
pub unsafe extern "C" fn uservec() {
    asm!(
        "
            .altmacro
            SAVE_GENERAL_REGS
            csrw    sscratch, x0

            .word   0x10813827
            .word   0x10913c27

            mv      a0, sp
            ld      sp, 0*8(a0)
            sd      x0, 0*8(a0)

            ld      gp, 8*2(sp)
            ld      tp, 8*3(sp)
            ld      s0, 8*4(sp)
            ld      s1, 8*5(sp)
            ld      s2, 8*6(sp)
            ld      s3, 8*7(sp)
            ld      s4, 8*8(sp)
            ld      s5, 8*9(sp)
            ld      s6, 8*10(sp)
            ld      s7, 8*11(sp)
            ld      s8, 8*12(sp)
            ld      s9, 8*13(sp)
            ld      s10, 8*14(sp)
            ld      s11, 8*15(sp)
            ld      ra, 8*17(sp)
            ld      sp, 8(sp)
            addi    sp, sp, 18*8
            ret
        ",
        options(noreturn)
    );
}

pub fn run_user_task(context: &mut TrapFrame) -> Option<()> {
    user_restore(context);
    match kernel_callback(context) {
        TrapType::UserEnvCall => Some(()),
        _ => None,
    }
}

