/// manage a frame which has the same lifecycle as the tracker
#[derive(Clone)]
pub struct FrameTracker {
    ///
    pub ppn: PhysPageNum,
}

impl FrameTracker {
    ///Create an empty `FrameTracker`
    pub fn new(ppn: PhysPageNum) -> Self {
        // page cleaning
        ppn.drop_clear();
        Self { ppn }
    }

    /// Physical base address of the frame.
    pub fn paddr(&self) -> usize {
        self.ppn.to_addr()
    }

    /// Mutable byte view of the whole frame.
    pub fn bytes_mut(&self) -> &'static mut [u8] {
        self.ppn.get_buffer()
    }
}

impl Debug for FrameTracker {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        f.write_fmt(format_args!("FrameTracker:PPN={:#x}", self.ppn.as_num()))
    }
}

impl Drop for FrameTracker {
    fn drop(&mut self) {
        frame_dealloc(self.ppn);
    }
}

trait FrameAllocator {
    fn new() -> Self;
    fn alloc(&mut self) -> Option<PhysPageNum>;
    fn alloc_more(&mut self, pages: usize) -> Option<Vec<PhysPageNum>>;
    fn dealloc(&mut self, ppn: PhysPageNum);
}
/// an implementation for frame allocator
pub struct StackFrameAllocator {
    current: usize,
    end: usize,
    recycled: Vec<usize>,
}

impl StackFrameAllocator {
    pub fn init(&mut self, l: PhysPageNum, r: PhysPageNum) {
        self.current = l.as_num();
        self.end = r.as_num();
        log_info!("last {} Physical Frames.", self.end - self.current);
    }
}
impl FrameAllocator for StackFrameAllocator {
    fn new() -> Self {
        Self {
            current: 0,
            end: 0,
            recycled: Vec::new(),
        }
    }
    fn alloc(&mut self) -> Option<PhysPageNum> {
        //println!("申请 recycled frames: {:x?}", self.recycled);
        if let Some(ppn) = self.recycled.pop() {
            log_debug!("alloc:0x{:x}",ppn);
            Some(ppn.into())
        } else if self.current == self.end {
            None
        } else {
            self.current += 1;
            log_debug!("dealloc phys frame ppn:0x{:x}",self.current-1);
            Some((self.current - 1).into())
        }

    }
    fn alloc_more(&mut self, pages: usize) -> Option<Vec<PhysPageNum>> {
        if self.current + pages >= self.end {
            None
        } else {
            self.current += pages;
            let arr: Vec<usize> = (1..pages + 1).collect();
            let v = arr.iter().map(|x| (self.current - x).into()).collect();
            Some(v)
        }
    }
    fn dealloc(&mut self, ppn: PhysPageNum) {
        let ppn = ppn.as_num();
        log_debug!("dealloc phys frame ppn:0x{:x}",ppn);
        // validity check
        //println!("current={:x}",self.current);
        //println!("释放 recycled frames: {:x?}", self.recycled);
        if ppn >= self.current || self.recycled.iter().any(|&v| v == ppn) {
            panic!("Frame ppn={:#x} has not been allocated!", ppn);
        }
        // recycle
        self.recycled.push(ppn);
    }
}

type FrameAllocatorImpl = StackFrameAllocator;

lazy_static! {
        pub static ref FRAME_ALLOCATOR: Mutex<FrameAllocatorImpl> =
            Mutex::new(FrameAllocatorImpl::new());
}
/// initiate the frame allocator using `ekernel` and `MEMORY_END`
pub fn init_frame_allocator(mm_start:usize,mm_end:usize) {
    extern "C" {
        fn end();
    }
    let phys_end = end as usize;
    if phys_end >= mm_start && phys_end < mm_end {
        unsafe {
            core::slice::from_raw_parts_mut(
                phys_end as *mut u128,
                (mm_end - phys_end) / size_of::<u128>(),
            )
            .fill(0);
        }
        let start = ((phys_end + 0xfff) / PAGE_SIZE * PAGE_SIZE) & (!VIRT_ADDR_START);
        FRAME_ALLOCATOR.lock().init(
            PhysAddr::new(start).into(),
            PhysAddr::new(mm_end & (!VIRT_ADDR_START)).into(),
        );
    }
}
/// allocate a frame
pub fn frame_alloc() -> Option<FrameTracker> {
    FRAME_ALLOCATOR
        .lock()
        .alloc()
        .map(FrameTracker::new)
        .inspect(|x| x.ppn.drop_clear())
}
///
pub fn frame_alloc_persist() -> Option<PhysPageNum> {
    FRAME_ALLOCATOR
        .lock()
        .alloc()
        .inspect(|x| x.drop_clear())
}
///
pub fn frame_alloc_more(num: usize) -> Option<Vec<FrameTracker>> {
    FRAME_ALLOCATOR
        .lock()
        .alloc_more(num)
        .map(|x| x.iter().map(|&t| FrameTracker::new(t)).collect())
}
/// deallocate a frame
pub fn frame_dealloc(ppn: PhysPageNum) {
    FRAME_ALLOCATOR.lock().dealloc(ppn);
}

