}

pub fn user_translated_bytes(inner: &TaskControlBlockInner, ptr: *const u8, len: usize) -> SysResult<&'static [u8]> {
    inner.ensure_user_range(ptr as usize, len, false)?;
    unsafe { Ok(core::slice::from_raw_parts(ptr, len)) }
}

pub fn user_translated_bytes_mut(
    inner: &TaskControlBlockInner,
    ptr: *mut u8,
    len: usize,
) -> SysResult<&'static mut [u8]> {
    inner.ensure_user_range(ptr as usize, len, true)?;
    unsafe { Ok(core::slice::from_raw_parts_mut(ptr, len)) }
}

pub fn user_translated_read_buffer<T>(
    inner: &TaskControlBlockInner,
    ptr: *mut T,
    len: usize,
) -> SysResult<&'static mut [T]> {
    inner.ensure_user_range(ptr as usize, len * core::mem::size_of::<T>(), false)?;
    unsafe { Ok(core::slice::from_raw_parts_mut(ptr, len)) }
}

pub fn user_translated_write_buffer<T>(
    inner: &TaskControlBlockInner,
    ptr: *mut T,
    len: usize,
) -> SysResult<&'static mut [T]> {
    inner.ensure_user_range(ptr as usize, len * core::mem::size_of::<T>(), true)?;
    unsafe { Ok(core::slice::from_raw_parts_mut(ptr, len)) }
}

pub fn user_safe_translated_str(inner: &TaskControlBlockInner, ptr: *const u8) -> SysResult<String> {
    let mut len = 0usize;
    loop {
        inner.ensure_user_range(ptr as usize + len, 1, false)?;
        let byte = unsafe { *ptr.add(len) };
        if byte == 0 {
            break;
        }
        len += 1;
    }
    let slice = unsafe { core::slice::from_raw_parts(ptr, len) };
    Ok(core::str::from_utf8(slice).map_err(|_| SysError::EINVAL)?.to_string())
}

/// Suspend the current 'Running' task and run the next task in task list.
pub fn suspend_current_and_run_next() {
    // There must be an application running.
    let task = take_current_task().unwrap();
    log_info!("task:{} suspend", task.getpid()); //最好不要显示这个
                                                 // ---- access current TCB exclusively
    task.check_itimer();
    //check timerfd in fd_table
    if task.inner_exclusive_access().timerfd_cnt > 0 {
        task.check_timerfd();
    }
    let mut task_inner = task.inner_exclusive_access();
    let task_cx_ptr = &mut task_inner.task_cx as *mut KContext;
    // Change status to Ready
    if task_inner.task_status != TaskStatus::Blocked {
        task_inner.task_status = TaskStatus::Ready;
    }
    drop(task_inner);
    // ---- release current PCB

    // push back to ready queue.
    add_task(task);
    // jump to scheduling cycle
    schedule(task_cx_ptr);
    if let Some((code, _msg)) = check_signals_error_of_current() {
        //println!("Process terminated due to signal: {}", _msg);
        exit_current_and_run_next(code as i32);
        unreachable!("Should have exited");
    }
}
///
pub fn block_current_and_run_next() {
    // There must be an application running.
    let task = take_current_task().unwrap();
    // println!("task:{} blocked",task.gettid());//最好不要显示这个
    // ---- access current TCB exclusively
    let mut task_inner = task.inner_exclusive_access();
    let task_cx_ptr = &mut task_inner.task_cx as *mut KContext;
    // Change status to Ready
    task_inner.task_status = TaskStatus::Blocked;
    drop(task_inner);
    // ---- release current PCB

    // push back to block queue.
    add_blocked_task(task);
    // jump to scheduling cycle
    schedule(task_cx_ptr);
}
