struct GuardSlot(UnsafeCell<Option<MutexGuard<'static, ()>>>);

unsafe impl Sync for GuardSlot {}

impl GuardSlot {
    const fn new() -> Self {
        Self(UnsafeCell::new(None))
    }

    unsafe fn is_locked(&self) -> bool {
        (*self.0.get()).is_some()
    }

    unsafe fn store(&self, guard: MutexGuard<'static, ()>) {
        *self.0.get() = Some(guard);
    }

    unsafe fn take(&self) -> Option<MutexGuard<'static, ()>> {
        (*self.0.get()).take()
    }
}

static MOUNT_LOCK: Mutex<()> = Mutex::new(());
static MOUNT_LOCK_GUARD: GuardSlot = GuardSlot::new();

unsafe extern "C" fn mount_lock() {
    if MOUNT_LOCK_GUARD.is_locked() {
        log::error!("[lwext4] mount lock requested while already held");
        return;
    }
    MOUNT_LOCK_GUARD.store(MOUNT_LOCK.lock());
}

unsafe extern "C" fn mount_unlock() {
    if MOUNT_LOCK_GUARD.take().is_none() {
        log::error!("[lwext4] mount unlock requested while not held");
    }
}

static EXT4_LOCKS: ffi::Ext4Lock = ffi::Ext4Lock {
    lock: Some(mount_lock),
    unlock: Some(mount_unlock),
};

fn map_err(rc: c_int) -> Result<(), c_int> {
    if rc == 0 { Ok(()) } else { Err(rc) }
}

pub fn register_device(dev_name: &str, device: Arc<dyn BlockDevice>, block_count: u64) -> Result<(), c_int> {
    let c_name = CString::new(dev_name).map_err(|_| -1)?;
    let bdev = blockdev::init_blockdev(device, block_count);
    let rc = unsafe { ffi::ext4_device_register(bdev, c_name.as_ptr()) };
    map_err(rc)
}

pub fn mount(dev_name: &str, mount_point: &str, read_only: bool) -> Result<(), c_int> {
    let c_dev = CString::new(dev_name).map_err(|_| -1)?;
    let c_mp = CString::new(mount_point).map_err(|_| -1)?;
    let rc = unsafe { ffi::ext4_mount(c_dev.as_ptr(), c_mp.as_ptr(), read_only) };
    map_err(rc)?;

    let rc = unsafe { ffi::ext4_mount_setup_locks(c_mp.as_ptr(), &EXT4_LOCKS) };
    if rc != 0 {
        let _ = unsafe { ffi::ext4_umount(c_mp.as_ptr()) };
        return Err(rc);
    }

    Ok(())
}

pub fn umount(mount_point: &str) -> Result<(), c_int> {
    let c_mp = CString::new(mount_point).map_err(|_| -1)?;
    let rc = unsafe { ffi::ext4_umount(c_mp.as_ptr()) };
    map_err(rc)
}

pub fn disk_sync(path: &str) -> Result<(), c_int> {
    let c_path = CString::new(path).map_err(|_| -1)?;
    let rc = unsafe { ffi::ext4_cache_flush(c_path.as_ptr()) };
    map_err(rc)
}

