pub const DISK_BLOCK_SIZE: usize = 512;

struct GuardSlot(UnsafeCell<Option<MutexGuard<'static, ()>>>);

unsafe impl Sync for GuardSlot {}

impl GuardSlot {
    const fn new() -> Self {
        Self(UnsafeCell::new(None))
    }

    unsafe fn is_locked(&self) -> bool {
        (*self.0.get()).is_some()
    }

    unsafe fn store(&self, guard: MutexGuard<'static, ()>) {
        *self.0.get() = Some(guard);
    }

    unsafe fn take(&self) -> Option<MutexGuard<'static, ()>> {
        (*self.0.get()).take()
    }
}

static DEVICE: Mutex<Option<Arc<dyn BlockDevice>>> = Mutex::new(None);
static IO_LOCK: Mutex<()> = Mutex::new(());
static IO_LOCK_GUARD: GuardSlot = GuardSlot::new();

static mut PH_BBUF: [u8; DISK_BLOCK_SIZE] = [0; DISK_BLOCK_SIZE];

fn trace_first_u64(buf: &[u8]) -> Option<u64> {
    if buf.len() < 8 {
        return None;
    }
    Some(u64::from_le_bytes([
        buf[0], buf[1], buf[2], buf[3], buf[4], buf[5], buf[6], buf[7],
    ]))
}

fn trace_block_io(op: &str, blk_id: u64, blk_cnt: u32, buf: &[u8]) {
    log::info!(
        "[lwext4-blockdev] {} blk_id={} blk_cnt={} first8=0x{:016x}",
        op,
        blk_id,
        blk_cnt,
        trace_first_u64(buf).unwrap_or(0)
    );
}

unsafe extern "C" fn bdev_open(_bdev: *mut Ext4Blockdev) -> c_int { 0 }
unsafe extern "C" fn bdev_close(_bdev: *mut Ext4Blockdev) -> c_int { 0 }
unsafe extern "C" fn bdev_lock(_bdev: *mut Ext4Blockdev) -> c_int {
    if IO_LOCK_GUARD.is_locked() {
        log::error!("[lwext4] blockdev lock requested while already held");
        return -1;
    }
    IO_LOCK_GUARD.store(IO_LOCK.lock());
    0
}
unsafe extern "C" fn bdev_unlock(_bdev: *mut Ext4Blockdev) -> c_int {
    if IO_LOCK_GUARD.take().is_none() {
        log::error!("[lwext4] blockdev unlock requested while not held");
        return -1;
    }
    0
}

unsafe extern "C" fn bdev_bread(_bdev: *mut Ext4Blockdev, buf: *mut c_void, blk_id: u64, blk_cnt: u32) -> c_int {
    let guard = DEVICE.lock();
    let Some(dev) = guard.as_ref() else {
        return -1;
    };

    let out = unsafe { slice::from_raw_parts_mut(buf as *mut u8, blk_cnt as usize * DISK_BLOCK_SIZE) };
    for i in 0..blk_cnt as usize {
        let start = i * DISK_BLOCK_SIZE;
        let end = start + DISK_BLOCK_SIZE;
        dev.read_block(blk_id as usize + i, &mut out[start..end]);
    }
    trace_block_io("bread", blk_id, blk_cnt, out);
    0
}

unsafe extern "C" fn bdev_bwrite(_bdev: *mut Ext4Blockdev, buf: *const c_void, blk_id: u64, blk_cnt: u32) -> c_int {
    let guard = DEVICE.lock();
    let Some(dev) = guard.as_ref() else {
        return -1;
    };

    let input = unsafe { slice::from_raw_parts(buf as *const u8, blk_cnt as usize * DISK_BLOCK_SIZE) };
    trace_block_io("bwrite", blk_id, blk_cnt, input);
    for i in 0..blk_cnt as usize {
        let start = i * DISK_BLOCK_SIZE;
        let end = start + DISK_BLOCK_SIZE;
        dev.write_block(blk_id as usize + i, &input[start..end]);
    }
    let mut readback = [0u8; DISK_BLOCK_SIZE];
    dev.read_block(blk_id as usize, &mut readback);
    trace_block_io("bwrite-readback", blk_id, 1, &readback);
    0
}

