/// The socket returned by `socket(AF_ALG, ...)` and configured by `bind` /
/// `setsockopt`. `accept()` clones its configuration into an [`AlgRequest`].
pub struct AlgSocket {
    inner: FileInner,
    state: Mutex<AlgBindState>,
}

struct AlgBindState {
    /// Selected algorithm, set by `bind()`.
    kind: Option<AlgKind>,
    /// Optional key, set by `setsockopt(ALG_SET_KEY)`.
    key: Option<Vec<u8>>,
}

impl AlgSocket {
    fn new(dentry: Arc<dyn Dentry>) -> Self {
        Self {
            inner: FileInner::new(dentry),
            state: Mutex::new(AlgBindState {
                kind: None,
                key: None,
            }),
        }
    }

    fn bind(&self, kind: AlgKind) {
        self.state.lock().kind = Some(kind);
    }

    fn set_key(&self, key: Vec<u8>) {
        self.state.lock().key = Some(key);
    }

    fn kind(&self) -> Option<AlgKind> {
        self.state.lock().kind
    }

    /// Snapshot `(kind, key)` for `accept()`. Fails with `EINVAL` if the socket
    /// was never bound to an algorithm.
    fn snapshot(&self) -> SysResult<(AlgKind, Option<Vec<u8>>)> {
        let st = self.state.lock();
        let kind = st.kind.ok_or(SysError::EINVAL)?;
        Ok((kind, st.key.clone()))
    }
}

