/// Resolve a bare hash name (no `hmac(...)` wrapper). Accepts both the short
/// name (`"sha256"`) and the driver name (`"sha256-generic"`) that LTP probes.
fn lookup_hash(name: &str) -> Option<HashAlg> {
    let base = name.strip_suffix("-generic").unwrap_or(name);
    let alg = match base {
        "md5" => HashAlg::Md5,
        "sha1" => HashAlg::Sha1,
        "sha224" => HashAlg::Sha224,
        "sha256" => HashAlg::Sha256,
        "sha384" => HashAlg::Sha384,
        "sha512" => HashAlg::Sha512,
        "sha3-256" => HashAlg::Sha3_256,
        "sha3-512" => HashAlg::Sha3_512,
        "sm3" => HashAlg::Sm3,
        _ => return None,
    };
    Some(alg)
}

