/// the ciphers af_alg04 probes (`aes`, `sm4`, `sm4-generic`).
fn is_vmac_name(name: &str) -> bool {
    let inner = name
        .strip_prefix("vmac64(")
        .or_else(|| name.strip_prefix("vmac("))
        .and_then(|s| s.strip_suffix(')'));
    match inner {
        Some(i) => {
            let base = i.strip_suffix("-generic").unwrap_or(i);
            base == "aes" || base == "sm4"
        }
        None => false,
    }
}

