// ---- ABI structs (Linux include/uapi/linux/aio_abi.h) ----------------------

/// `struct iocb` — one queued I/O request as laid out by userspace libaio.
#[repr(C)]
#[derive(Clone, Copy)]
pub struct Iocb {
    /// `aio_data`: opaque cookie echoed back in the completion event.
    pub aio_data: u64,
    /// `aio_key` / `aio_rw_flags` (PADDED). Unused by us.
    pub aio_key_rw_flags: u32,
    /// padding to keep `aio_lio_opcode` at the ABI offset.
    pub aio_reserved1: u32,
    /// operation code, see the `IOCB_CMD_*` constants.
    pub aio_lio_opcode: u16,
    /// request priority (ignored).
    pub aio_reqprio: i16,
    /// file descriptor to operate on.
    pub aio_fildes: u32,
    /// user buffer address (read target / write source).
    pub aio_buf: u64,
    /// number of bytes to transfer.
    pub aio_nbytes: u64,
    /// file offset for the transfer.
    pub aio_offset: i64,
    /// reserved.
    pub aio_reserved2: u64,
    /// `aio_flags` (e.g. `IOCB_FLAG_RESFD`).
    pub aio_flags: u32,
    /// eventfd for completion notification when `IOCB_FLAG_RESFD` is set.
    pub aio_resfd: u32,
}

/// `struct io_event` — one completion record handed back by `io_getevents`.
#[repr(C)]
#[derive(Clone, Copy, Default)]
pub struct IoEvent {
    /// echo of `iocb.aio_data`.
    pub data: u64,
    /// the userspace `iocb` pointer that was submitted.
    pub obj: u64,
    /// primary result: bytes transferred, or a negative errno.
    pub res: i64,
    /// secondary result (always 0 here).
    pub res2: i64,
}

// ---- opcodes ---------------------------------------------------------------

/// `IOCB_CMD_PREAD` — positioned read into `aio_buf`.
pub const IOCB_CMD_PREAD: u16 = 0;
/// `IOCB_CMD_PWRITE` — positioned write from `aio_buf`.
pub const IOCB_CMD_PWRITE: u16 = 1;
/// `IOCB_CMD_FSYNC`.
pub const IOCB_CMD_FSYNC: u16 = 2;
/// `IOCB_CMD_FDSYNC`.
pub const IOCB_CMD_FDSYNC: u16 = 3;
/// `IOCB_CMD_PREADV` — vectored positioned read.
pub const IOCB_CMD_PREADV: u16 = 7;
/// `IOCB_CMD_PWRITEV` — vectored positioned write.
pub const IOCB_CMD_PWRITEV: u16 = 8;

/// Whether `op` is an opcode this subsystem recognizes (validated by
/// `io_submit` before a request is queued, matching Linux behaviour).
pub fn opcode_valid(op: u16) -> bool {
    matches!(
        op,
        IOCB_CMD_PREAD
            | IOCB_CMD_PWRITE
            | IOCB_CMD_FSYNC
            | IOCB_CMD_FDSYNC
            | IOCB_CMD_PREADV
            | IOCB_CMD_PWRITEV
    )
}

// ---- per-request descriptor (kernel side) ----------------------------------

/// A single submitted request, with everything the engine needs that is *not*
/// bound to user memory. The user data buffer is passed to [`AioEngine::submit`]
/// separately as a kernel-visible slice (already translated by the syscall
/// layer), so this struct stays free of raw user pointers.
pub struct AioRequest {
    /// operation, one of the `IOCB_CMD_*` constants.
    pub opcode: u16,
    /// the target file (resolved from `aio_fildes`).
    pub file: Arc<dyn File>,
    /// file offset.
    pub offset: usize,
    /// echoed back as `IoEvent.data`.
    pub data: u64,
    /// the userspace `iocb` pointer, echoed back as `IoEvent.obj`.
    pub obj: u64,
}

