const CPUCFG1_UAL: usize = 1 << 20;
const CPUCFG1_CRC32: usize = 1 << 25;
const CPUCFG2_FP: usize = 1 << 0;
const HWCAP_LOONGARCH_CPUCFG: usize = 1 << 0;
const HWCAP_LOONGARCH_UAL: usize = 1 << 2;
const HWCAP_LOONGARCH_FPU: usize = 1 << 3;
const HWCAP_LOONGARCH_CRC32: usize = 1 << 6;

fn loongarch_cpu_hwcaps() -> usize {
    let cfg1 = CPUCFG::read(1).get_bits(0, usize::BITS as usize - 1);
    let cfg2 = CPUCFG::read(2).get_bits(0, usize::BITS as usize - 1);

    let mut hwcap = HWCAP_LOONGARCH_CPUCFG;
    if cfg1 & CPUCFG1_UAL != 0 {
        hwcap |= HWCAP_LOONGARCH_UAL;
    }
    if cfg1 & CPUCFG1_CRC32 != 0 {
        hwcap |= HWCAP_LOONGARCH_CRC32;
    }
    if cfg2 & CPUCFG2_FP != 0 {
        hwcap |= HWCAP_LOONGARCH_FPU;
    }
    hwcap
}

pub fn user_hwcaps() -> usize {
    loongarch_cpu_hwcaps()
}

pub fn rust_tmp_main() {
    clear_bss();
    console_init();
    ArchInterface::init_logging();
    log::error!("console init!");
    ArchInterface::init_allocator();
    trap::set_trap_vector_base();
    sigtrx::init();

    // High RAM begins at physical 0x9000_0000 on the loongarch `virt` machine.
    // This 512 MiB span (..0xB000_0000) is the known-good, empirically-validated
    // range. Extending it to 0xC000_0000 (assuming `-m 1G`) faulted the kernel
    // at boot — the actual run apparently does NOT provide RAM that far, so the
    // frame allocator handed out frames past the end of physical memory and the
    // first kernel access to one took a page fault (main.rs:108, no current
    // task). Do not raise this constant blindly; the correct fix is to parse the
    // QEMU-provided FDT `/memory` node (the `fdt` crate is already a dependency
    // and `add_memory_region` was designed for exactly this) — see
    // docs/memory-region-dtb.md.
    ArchInterface::add_memory_region(
        VIRT_ADDR_START | 0x9000_0000,
        VIRT_ADDR_START | (0x9000_0000 + 0x2000_0000),
    );

    ArchInterface::prepare_drivers();

    let hwcap = loongarch_cpu_hwcaps();
    euen::set_fpe(hwcap & HWCAP_LOONGARCH_FPU != 0);
    // Enable the LSX/LASX vector units in hardware (EUEN). This is orthogonal to
    // what we advertise in AT_HWCAP: `loongarch_cpu_hwcaps()` deliberately does
    // NOT set the LSX/LASX bits, so glibc/musl IFUNC resolvers will not select
    // vector-optimized paths (the conservative-HWCAP intent is preserved).
    //
    // However, some user binaries emit LSX instructions unconditionally (e.g.
    // anything built with -mlsx, like the contest's `mmap_once`). With the
    // units disabled those instructions raise an SXD/ASXD exception that the
    // estat decoder reports as `Unknown` -> kernel panic. Enabling the units
    // lets such code execute. Fidelity matches FP handling: the kernel does not
    // context-switch FP/vector registers either, so this is the same model FP
    // already uses successfully.
    euen::set_sxe(true);
    euen::set_asxe(true);
    timer::init_timer();
    trap::init_interrupt();
    trap::enable_external_irq();

    ArchInterface::main();

    shutdown();
}
