pub fn register_all_fs(){
    let mut file_systems = FILE_SYSTEMS.lock();
    let _ = file_systems.register_fs("LwExt4".to_string(), Arc::new(LwExt4FsType::new()));
    let _ = file_systems.register_fs("tmpfs".to_string(), TmpFsType::new());
    let _ = file_systems.register_fs("procfs".to_string(), ProcFsType::new());
    let _ = file_systems.register_fs("devfs".to_string(), DevFsType::new());
}

pub fn init(){
    register_all_fs();
    let root_fs = FILE_SYSTEMS.lock().file_systems.get(ROOT_FS).unwrap().clone();
    let root_dentry = root_fs.mount("/", None,MountFlags::empty(),Some(BLOCK_DEVICE.get().unwrap().clone())).unwrap();

    let dev_fs = FILE_SYSTEMS.lock().file_systems.get("devfs").unwrap().clone();
    let dev_dentry = dev_fs.mount("dev", Some(root_dentry.clone()), MountFlags::empty(), None).unwrap();
    let _ = init_devfs(dev_dentry);

    let proc_fs = FILE_SYSTEMS.lock().file_systems.get("procfs").unwrap().clone();
    let proc_dentry = proc_fs.mount("proc", Some(root_dentry.clone()), MountFlags::empty(), None).unwrap();
    let _ = init_procfs(proc_dentry);

    let tmp_fs = FILE_SYSTEMS.lock().file_systems.get("tmpfs").unwrap().clone();
    let _dev_dentry = tmp_fs.mount("tmp", Some(root_dentry.clone()), MountFlags::empty(), None).unwrap();

    init_sysfs_block(root_dentry.clone()).unwrap();

    ROOT_DENTRY.call_once(|| root_dentry);

}

fn init_sysfs_block(root_dentry: Arc<dyn Dentry>) -> SysResult<()> {
    let sb = root_dentry.get_superblock();
    let sys_dentry: Arc<dyn Dentry> = MemDentry::new("sys", sb.clone(), Some(root_dentry.clone()));
    let sys_inode = MemInode::new(InodeMode::DIR | InodeMode::all_perm(), sb.clone(), 0, 0);
    sys_dentry.set_inode(sys_inode);
    *sys_dentry.get_state() = vfs_defs::DentryState::Valid;

    let block_dentry = sys_dentry.create("block", InodeMode::DIR | InodeMode::all_perm(), 0, 0)?;
    for entry in block_device_entries() {
        let device_dentry = block_dentry.create(entry.name, InodeMode::DIR | InodeMode::all_perm(), 0, 0)?;
        let size_dentry = device_dentry.create("size", InodeMode::FILE | InodeMode::all_perm(), 0, 0)?;
        let size_file = size_dentry.open(vfs_defs::OpenFlags::RDWR);
        let sectors = entry.blocks * BLOCK_SIZE / 512;
        let _ = size_file.write(format!("{}\n", sectors).as_bytes());
    }

    root_dentry.add_child(sys_dentry);
    Ok(())
}

pub fn get_root_dentry() -> Arc<dyn Dentry> {
    ROOT_DENTRY.get().unwrap().clone()
}

