pub struct LwExt4Inode {
    meta: InodeMeta,
    path: Mutex<String>,
}

impl LwExt4Inode {
    pub fn new(meta: InodeMeta, path: String) -> Self {
        Self { meta, path: Mutex::new(path) }
    }

    pub fn path(&self) -> String {
        self.path.lock().clone()
    }

    pub fn set_path(&self, path: String) {
        *self.path.lock() = path;
    }

    fn fill_basic_meta(&self) -> SysResult<()> {
        let path = self.path();
        let cpath = CString::new(path.as_str()).map_err(|_| SysError::EINVAL)?;

        let mut mode: u32 = 0;
        cvt(unsafe { ffi::ext4_mode_get(cpath.as_ptr(), &mut mode) })?;

        let mut uid: u32 = 0;
        let mut gid: u32 = 0;
        cvt(unsafe { ffi::ext4_owner_get(cpath.as_ptr(), &mut uid, &mut gid) })?;

        let mut inner = self.meta.inner.lock();
        inner.mode = InodeMode::from_bits_truncate(mode);
        inner.uid = uid as u16;
        inner.gid = gid as u16;
        Ok(())
    }

    /// Filesystem block size of the root ext4 mount. Reported as st_blksize so
    /// userspace (e.g. LTP lseek11's SEEK_DATA/SEEK_HOLE block-size probe) sees
    /// the real allocation granularity instead of 0.
    fn fs_block_size(&self) -> u32 {
        let cmp = match CString::new("/") {
            Ok(s) => s,
            Err(_) => return 4096,
        };
        let mut stats: ffi::Ext4MountStats = unsafe { core::mem::zeroed() };
        if unsafe { ffi::ext4_mount_point_stats(cmp.as_ptr(), &mut stats) } == 0
            && stats.block_size != 0
        {
            stats.block_size
        } else {
            4096
        }
    }
}

impl Inode for LwExt4Inode {

    fn load_from_disk(&self) {
        let _ = self.fill_basic_meta();
    }

    //ok
    fn get_meta(&self) -> &InodeMeta {
        &self.meta
    }
    //ok
    fn get_attr(&self) -> SysResult<Kstat> {
        self.fill_basic_meta()?;
        let size = self.get_size();
        let inner = self.meta.inner.lock();
        Ok(Kstat {
            st_ino: self.meta.ino as u64,
            st_mode: inner.mode.bits(),
            st_nlink: inner.link,
            st_uid: inner.uid as u32,
            st_gid: inner.gid as u32,
            st_size: size as u64,
            st_blksize: self.fs_block_size(),
            ..Kstat::default()
        })
    }
