    // in-memory copy, but get_attr/fill_basic_meta re-reads the mode from disk
    // every time, so without writing it through, bits set here (e.g. execute on
    // provisioned busybox) are lost on the next stat.
    fn set_mode(&self, mode: InodeMode) {
        let perm = mode & InodeMode::from_bits_truncate(0o7777);
        {
            let mut inner = self.meta.inner.lock();
            inner.mode = (inner.mode & !InodeMode::from_bits_truncate(0o7777)) | perm;
