    mount_devices: Mutex<BTreeMap<String, String>>, // mount_path -> dev_name
}


fn check_mount_health_warn_only(mount_path: &str) {
    let c_mount = CString::new(mount_path).expect("mount path should be valid c string");

    let recover_rc = unsafe { ffi::ext4_recover(c_mount.as_ptr()) };
    if recover_rc != 0 {
        log::error!(
            "[boot-check] warning: ext4 recover failed for mount {} rc={}",
            mount_path,
            recover_rc
        );
        return;
    }

    let mut sb_ptr: *mut ffi::Ext4Sblock = core::ptr::null_mut();
    let rc = unsafe { ffi::ext4_get_sblock(c_mount.as_ptr(), &mut sb_ptr) };
    if rc != 0 || sb_ptr.is_null() {
        log::error!(
            "[boot-check] warning: ext4 get_sblock failed for mount {} rc={} sb_ptr={:?}",
            mount_path,
            rc,
            sb_ptr
        );
        return;
    }

    let state = unsafe { (*sb_ptr).state };
    let error_policy = unsafe { (*sb_ptr).errors };
    let has_error = (state & ffi::EXT4_SUPERBLOCK_STATE_ERROR_FS) != 0;

    if has_error {
        log::error!(
            "[boot-check] warning: ext4 unhealthy on mount {} after recover: state=0x{:x}, errors_policy={} (ERROR_FS still set)",
            mount_path,
            state,
            error_policy
        );
    }
}

impl LwExt4FsType {
    pub fn new() -> Self {
        Self {
            inner: FileSystemTypeInner::new(String::from("LwExt4")),
            mount_devices: Mutex::new(BTreeMap::new()),
        }
    }

    fn normalize_mount_path(name: &str, parent: Option<&Arc<dyn Dentry>>) -> String {
        if parent.is_none() {
            return String::from("/");
        }
        let base = parent.unwrap().path();
        let clean = name.trim_matches('/');
        if clean.is_empty() {
            return base;
        }
        if base == "/" {
            format!("/{}", clean)
        } else {
            format!("{}/{}", base, clean)
        }
    }

    /// lwext4's `ext4_mount`/`ext4_umount` require the mount point string to end
    /// with '/' (they `return ENOTSUP` otherwise — which our `cvt` then maps to
    /// the generic EIO). Root ("/") already satisfies this; sub-directory mount
    /// points like "/glibc/basic/mnt" do not, so normalize before the C call.
    fn c_mount_path(mount_path: &str) -> String {
        if mount_path.ends_with('/') {
            String::from(mount_path)
        } else {
            format!("{}/", mount_path)
        }
    }

    fn make_dev_name(mount_path: &str) -> String {
        if mount_path == "/" {
            return String::from("os2_root");
        }
        let mut s = String::from("os2");
        for ch in mount_path.chars() {
            if ch == '/' {
                s.push('_');
            } else {
                s.push(ch);
            }
        }
        s
    }
}

impl FileSystemType for LwExt4FsType {
    //ok
    fn get_inner(&self) -> &FileSystemTypeInner {
        &self.inner
    }
    //ok
    fn mount(
        self: Arc<Self>,
        name: &str,
        parent: Option<Arc<dyn Dentry>>,
        flags: MountFlags,
        device: Option<Arc<dyn BlockDevice>>,
     ) -> SysResult<Arc<dyn Dentry>> {
        let abs_mount_path = Self::normalize_mount_path(name, parent.as_ref());
        let read_only = flags.contains(MountFlags::MS_RDONLY);


        if let Some(dev) = device.clone() {
            let reported = dev.block_count();
            let block_count = if reported > 0 { reported } else { DEFAULT_BLOCK_COUNT.load(Ordering::Relaxed) };
            let bdev = blockdev::init_blockdev(dev, block_count);
            let dev_name = Self::make_dev_name(abs_mount_path.as_str());
            let c_dev_name = CString::new(dev_name.as_str()).map_err(|_| SysError::EINVAL)?;
            let c_mount = CString::new(Self::c_mount_path(abs_mount_path.as_str()))
                .map_err(|_| SysError::EINVAL)?;

            cvt(unsafe { ffi::ext4_device_register(bdev, c_dev_name.as_ptr()) })?;
            let mount_rc = unsafe { ffi::ext4_mount(c_dev_name.as_ptr(), c_mount.as_ptr(), read_only) };
            if let Err(e) = cvt(mount_rc) {
                let _ = unsafe { ffi::ext4_device_unregister(c_dev_name.as_ptr()) };
                return Err(e);
            }

            check_mount_health_warn_only(abs_mount_path.as_str());

            self.mount_devices.lock().insert(abs_mount_path.clone(), dev_name);
        }

        let inner = SuperBlockInner::new(device, self.clone());
        let superblock = Arc::new(LwExt4Superblock::new(inner));
        superblock.set_read_only(read_only);
        let mut stored_flags = MountFlags::from_bits_truncate(flags.bits());
        stored_flags.remove(MountFlags::MS_REMOUNT);
        superblock.set_mount_flags(stored_flags);

        let root_dentry: Arc<dyn Dentry> = if let Some(parent) = parent {
            Arc::new(LwExt4Dentry::new(DentryInner::new(
                name.trim_matches('/').to_string(),
                superblock.clone(),
                Some(parent),
            )))
        } else {
            Arc::new(LwExt4Dentry::new(DentryInner::new(
                String::from("/"),
                superblock.clone(),
                None,
            )))
        };

        let root_inode = Arc::new(LwExt4Inode::new(
            InodeMeta::new(
                InodeMode::DIR | InodeMode::all_perm(),
                2,
                superblock.clone(),
                0,
                0,
            ),
            abs_mount_path.clone(),
        ));
        root_inode.set_type(DiskInodeType::Directory);

        root_dentry.set_inode(root_inode);
        superblock.set_root_dentry(root_dentry.clone());
        self.add_superblock(abs_mount_path.as_str(), superblock);
        Ok(root_dentry)
    }
    //ok
    fn umount(self: Arc<Self>, path: &str, _flags: MountFlags) -> SysResult<()> {
        if let Some(dev_name) = self.mount_devices.lock().remove(path) {
            let c_mount = CString::new(Self::c_mount_path(path)).map_err(|_| SysError::EINVAL)?;
            let c_dev = CString::new(dev_name).map_err(|_| SysError::EINVAL)?;

            cvt(unsafe { ffi::ext4_umount(c_mount.as_ptr()) })?;
            cvt(unsafe { ffi::ext4_device_unregister(c_dev.as_ptr()) })?;
        }
        self.remove_superblock(path)
    }
}

