const TRACE_LWEXT4_FILE_IO: bool = false;
const FORCE_LWEXT4_FLUSH_AFTER_WRITE: bool = false;
const PROBE_LWEXT4_REREAD0: bool = false;

pub struct LwExt4File {
    inner: FileInner,
}

impl LwExt4File {
    pub fn new(inner: FileInner) -> Self {
        Self { inner }
    }

    fn trace_iozone_path(path: &str) -> bool {
        path.starts_with("/glibc/iozone.")
            || path.starts_with("/musl/iozone.")
            || path.starts_with("iozone.")
            || path.contains("/iozone.DUMMY")
            || path.starts_with("iozone.DUMMY")
    }

    fn trace_file_path(path: &str) -> bool {
        path.ends_with("/mm_plainfile.bin") || path.ends_with("/XXX") || Self::trace_iozone_path(path)
    }

    fn trace_first_u64(buf: &[u8]) -> u64 {
        let mut value = 0u64;
        let limit = core::cmp::min(buf.len(), 8);
        for i in 0..limit {
            value |= (buf[i] as u64) << (i * 8);
        }
        value
    }

    fn to_lw_flags(flags: OpenFlags) -> i32 {
        let mut f = if flags.contains(OpenFlags::RDWR) {
            ffi::O_RDWR
        } else if flags.contains(OpenFlags::WRONLY) {
            ffi::O_WRONLY
        } else {
            ffi::O_RDONLY
        };
        if flags.contains(OpenFlags::CREATE) {
            f |= ffi::O_CREAT;
        }
        if flags.contains(OpenFlags::TRUNC) {
            f |= ffi::O_TRUNC;
        }
        if flags.contains(OpenFlags::APPEND) {
            f |= ffi::O_APPEND;
        }
        f
    }

    fn with_open_file<T>(&self, flags: i32, f: impl FnOnce(&mut ffi::Ext4File) -> SysResult<T>) -> SysResult<T> {
        let path = self.get_dentry().path();
        let cpath = CString::new(path).map_err(|_| SysError::EINVAL)?;
        let mut file = ffi::Ext4File {
            mp: core::ptr::null_mut(),
            inode: 0,
            flags: 0,
            fsize: 0,
            fpos: 0,
        };
        let rc = unsafe { ffi::ext4_fopen2(&mut file, cpath.as_ptr(), flags) };
        cvt(rc)?;
        let out = f(&mut file);
        let _ = unsafe { ffi::ext4_fclose(&mut file) };
        out
    }
}

