pub const PIPE_MIN_SIZE: usize = arch::PAGE_SIZE;
pub const PIPE_DEFAULT_SIZE: usize = 16 * arch::PAGE_SIZE;
pub const RING_BUFFER_SIZE: usize = PIPE_MIN_SIZE;
pub const CAP_SYS_RESOURCE: u32 = 24;

pub fn current_task_has_pipe_size_privilege() -> bool {
    if let Some(task) = current_task() {
        let inner = task.inner_exclusive_access();
        has_pipe_size_privilege(inner.euid, inner.cap_effective)
    } else {
        false
    }
}

pub fn has_pipe_size_privilege(euid: usize, cap_effective: u64) -> bool {
    euid == 0 && (cap_effective & (1u64 << CAP_SYS_RESOURCE)) != 0
}

pub fn pipe_capacity_for_credentials(euid: usize, cap_effective: u64) -> usize {
    if has_pipe_size_privilege(euid, cap_effective) {
        PIPE_DEFAULT_SIZE
    } else {
        PIPE_DEFAULT_SIZE.min(vfs::get_pipe_max_size())
    }
}

fn default_pipe_capacity() -> usize {
    if current_task_has_pipe_size_privilege() {
        PIPE_DEFAULT_SIZE
    } else {
        PIPE_DEFAULT_SIZE.min(vfs::get_pipe_max_size())
    }
}

fn notify_pipe_read_end_async(read_end: Option<Arc<Pipe>>, written: usize) {
    if written == 0 {
        return;
    }
    if let Some(read_end) = read_end {
        if read_end.inner.flags.lock().contains(OpenFlags::ASYNC) {
            let file: Arc<dyn File> = read_end;
            crate::syscall::notify_file_async(&file);
        }
    }
}


