#[derive(Debug, PartialEq, Eq)]
pub enum TimerType {
    Futex,
    StoppedTask,
}

pub struct TimerCondVar {
    pub expire: TimeSpec,
    pub task: Weak<TaskControlBlock>,
    pub kind: TimerType,
    pub futex_wait_seq: u64,
}
impl PartialEq for TimerCondVar {
    fn eq(&self, other: &Self) -> bool {
        self.expire.sec == other.expire.sec && self.expire.nsec == other.expire.nsec
    }
}
impl Eq for TimerCondVar {}
impl PartialOrd for TimerCondVar {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        let a = -(self.expire.to_nsec() as isize);
        let b = -(other.expire.to_nsec() as isize);
        Some(a.cmp(&b))
    }
}
impl Ord for TimerCondVar {
    fn cmp(&self, other: &Self) -> Ordering {
        self.partial_cmp(other).unwrap()
    }
}

lazy_static! {
    pub static ref TIMERS: Mutex<BinaryHeap<TimerCondVar>> =
        Mutex::new(BinaryHeap::<TimerCondVar>::new());
}

pub fn add_futex_timer(expire: TimeSpec, task: Arc<TaskControlBlock>, futex_wait_seq: u64) {
    let mut timers = TIMERS.lock();
    timers.push(TimerCondVar {
        expire,
        task: Arc::downgrade(&task),
        kind: TimerType::Futex,
        futex_wait_seq,
    });
}

pub fn add_stopped_task_timer(expire: TimeSpec, task: Arc<TaskControlBlock>) {
    let mut timers = TIMERS.lock();
    timers.push(TimerCondVar {
        expire,
        task: Arc::downgrade(&task),
        kind: TimerType::StoppedTask,
        futex_wait_seq: 0,
    });
}

pub fn check_futex_timer() {
    let mut timers = TIMERS.lock();
    let current = get_curtime_spec();
    while let Some(timer) = timers.peek() {
        //println!("expire={:?}, current={:?}", timer.expire.to_nsec(), current);
        if timer.expire <= current {
            if let Some(task) = timer.task.upgrade() {
                if timer.kind == TimerType::Futex {
                    let mut inner = task.inner_exclusive_access();
                    if inner.futex_wait_seq == timer.futex_wait_seq && inner.futex_waiting {
                        // seq 匹配且任务仍在 futex_wait 阻塞中才算有效，
                        // 防止旧 timer 或已被 FUTEX_WAKE 唤醒的就绪任务收到虚假 ETIMEDOUT
                        inner.futex_timeout = true;
                        inner.futex_waiting = false;
                        drop(inner);
                        wakeup_task(Arc::clone(&task));
                    }
                } else if timer.kind == TimerType::StoppedTask {
                    todo!()
                    // wakeup_stopped_task(Arc::clone(&task));
                }
            }
            timers.pop();
        } else {
            break;
        }
    }
}

