impl MemorySet {
    pub fn new() -> Self {
        Self::default()
    }

    pub fn token(&self) -> PageTable {
        self.page_table.0
    }

    pub fn from_elf(elf_data: &[u8]) -> (Self, usize, usize, usize, usize, u16, u16, u64, usize) {
        let mut memory_set = Self::new();
        let elf = xmas_elf::ElfFile::new(elf_data).unwrap();
        let (max_virt_mem, _header_va, tls_addr, ph_count, phdr) = memory_set.map_elf_image(&elf, 0);

        let heap_start = max_virt_mem;
        let heap_limit = heap_start + USER_HEAP_SIZE;
        // The heap sits just past the ELF image, far below `USER_MMAP_TOP`, so it
        // is *outside* the mmap allocator's `[base, limit)` window. It is managed
        // purely as a VMA (see `expand_heap`/`sys_brk`); never register it with the
        // allocator — `reserve()` would fail `validate_range` (EADDRNOTAVAIL) and
        // the old `.unwrap()` here panicked the kernel on every exec.
        memory_set
            .vma_mgr
            .insert(
                VmaRecord {
                    range: VmaRange {
                        start: heap_start,
                        end: heap_limit,
                    },
                    perm: VmaPerm::R | VmaPerm::W | VmaPerm::U,
                    kind: VmaKind::Heap,
                    flags: 0,
                    backend: VmaBackend::Anonymous,
                },
                VmaInsertMode::Strict,
            )
            .unwrap();

        let user_stack_top = USER_STACK_TOP;
        let user_stack_bottom = user_stack_top - USER_STACK_SIZE;
        // The stack sits at the very top of the mmap allocator's window
        // (`user_stack_top == USER_STACK_TOP`, the allocator's `limit`), so unlike
        // the heap it *is* inside `[base, limit)`. Reserve it so the allocator
        // never hands a colliding address to a later `mmap`. This is in-range by
        // construction; a failure means the stack/allocator config drifted apart.
        memory_set
            .allocator
            .reserve(user_stack_bottom, user_stack_top - user_stack_bottom)
            .expect("user stack must lie within the mmap allocator window");
        memory_set
            .vma_mgr
            .insert(
                VmaRecord {
                    range: VmaRange {
                        start: user_stack_bottom,
                        end: user_stack_top,
                    },
                    perm: VmaPerm::R | VmaPerm::W | VmaPerm::U,
                    kind: VmaKind::Stack,
                    flags: 0,
                    backend: VmaBackend::Anonymous,
                },
                VmaInsertMode::Strict,
            )
            .unwrap();

        (
            memory_set,
            user_stack_top,
            elf.header.pt2.entry_point() as usize,
            heap_start,
            heap_limit,
            elf.header.pt2.ph_entry_size(),
            ph_count,
            tls_addr,
            phdr,
        )
    }

