impl LwExt4Dentry {
    pub fn new(inner: DentryInner) -> Self {
        Self { inner }
    }

    fn type_from_lw(t: u8) -> DiskInodeType {
        match t as i32 {
            ffi::EXT4_DE_REG_FILE => DiskInodeType::File,
            ffi::EXT4_DE_DIR => DiskInodeType::Directory,
            ffi::EXT4_DE_SYMLINK => DiskInodeType::SymLink,
            ffi::EXT4_DE_FIFO => DiskInodeType::Fifo,
            ffi::EXT4_DE_CHRDEV => DiskInodeType::CharDevice,
            ffi::EXT4_DE_SOCK => DiskInodeType::Socket,
            _ => DiskInodeType::None,
        }
    }

    fn try_fill_inode_for(self: &Arc<Self>, child: &Arc<dyn Dentry>, disk_type: DiskInodeType) -> SysResult<()> {
        let mut mode = InodeMode::from_type(disk_type);
        if mode == InodeMode::TYPE_MASK {
            mode = InodeMode::FILE | InodeMode::all_perm();
        }
        let inode = Arc::new(LwExt4Inode::new(
            vfs_defs::InodeMeta::new(mode, vfs_defs::ino_alloc(), self.get_superblock(), 0, 0),
            child.path(),
        ));
        inode.set_type(disk_type);
        child.set_inode(inode);
        *child.get_state() = DentryState::Valid;
        Ok(())
    }

    fn c_path(dentry: &Arc<dyn Dentry>) -> SysResult<CString> {
        CString::new(dentry.path()).map_err(|_| SysError::EINVAL)
    }

    fn probe_type_by_mode(path: &str) -> SysResult<DiskInodeType> {
        let cpath = CString::new(path).map_err(|_| SysError::EINVAL)?;
        let mut mode: u32 = 0;
        cvt(unsafe { ffi::ext4_mode_get(cpath.as_ptr(), &mut mode) })?;
        Ok(InodeMode::from_bits_truncate(mode).to_type())
    }
}

impl Dentry for LwExt4Dentry {
