    //在当前目录下创建一个name
    fn concrete_create(self: Arc<Self>, name: &str, mode: InodeMode, uid: u16, gid: u16) -> SysResult<Arc<dyn Dentry>> {
        let child = self.clone().get_child(name).unwrap_or_else(|| self.clone().concrete_new_child(name));
        let path = CString::new(child.path()).map_err(|_| SysError::EINVAL)?;

        let ty = DiskInodeType::from(mode);
        match ty {
            DiskInodeType::Directory => {
                cvt(unsafe { ffi::ext4_dir_mk(path.as_ptr()) })?;
            }
            DiskInodeType::File | DiskInodeType::None => {
                let mut f = ffi::Ext4File {
                    mp: core::ptr::null_mut(),
                    inode: 0,
                    flags: 0,
                    fsize: 0,
                    fpos: 0,
                };
                cvt(unsafe { ffi::ext4_fopen2(&mut f, path.as_ptr(), ffi::O_CREAT | ffi::O_RDWR) })?;
                let _ = unsafe { ffi::ext4_fclose(&mut f) };
            }
            DiskInodeType::SymLink | DiskInodeType::Socket | DiskInodeType::CharDevice | DiskInodeType::BlockDevice | DiskInodeType::Fifo => {
                return Err(SysError::ENOSYS);
            }
        }

        self.try_fill_inode_for(&child, ty)?;
        if let Ok(inode) = child.get_inode() {
            inode.set_uid(uid);
            inode.set_gid(gid);
            inode.set_mode(mode);
        }
        Ok(child)
    }
    //在当前目录找一个name
    fn concrete_lookup(self: Arc<Self>, name: &str) -> SysResult<Arc<dyn Dentry>> {
        let child = self.clone().get_child(name).unwrap_or_else(|| self.clone().concrete_new_child(name));
        let path = child.path();
        let dtype = Self::probe_type_by_mode(path.as_str())?;
        self.try_fill_inode_for(&child, dtype)?;
        Ok(child)
    }
    //先创建一个child，磁盘上没有
    fn concrete_new_child(self: Arc<Self>, name: &str) -> Arc<dyn Dentry> {
        let me: Arc<dyn Dentry> = self.clone();
        let child = Arc::new(LwExt4Dentry::new(DentryInner::new(String::from(name), self.get_superblock(), Some(me.clone()))));
        alloc_dentry(Some(&me), name, child.clone());
        child
    }
