const PIPE_MAX_SIZE_DEFAULT: usize = 1048576;
const PIPE_MAX_SIZE_MIN: usize = 4096;

lazy_static! {
    static ref PIPE_MAX_SIZE: Mutex<usize> = Mutex::new(PIPE_MAX_SIZE_DEFAULT);
}

pub fn get_pipe_max_size() -> usize {
    *PIPE_MAX_SIZE.lock()
}

pub fn set_pipe_max_size(size: usize) -> SysResult<()> {
    if size < PIPE_MAX_SIZE_MIN {
        return Err(SysError::EINVAL);
    }
    *PIPE_MAX_SIZE.lock() = size;
    Ok(())
}

