/// Bookkeeping for a single tmpfs mount so that `umount` can restore the
/// directory that the mount point shadowed (or remove the mount root entirely
/// when nothing was shadowed).
struct TmpMountInfo {
    parent: Arc<dyn Dentry>,
    name: String,
    shadowed: Option<Arc<dyn Dentry>>,
}

pub struct TmpFsType {
    inner: FileSystemTypeInner,
    /// Mount point path -> bookkeeping needed to undo the mount.
    mounts: Mutex<BTreeMap<String, TmpMountInfo>>,
}

impl TmpFsType {
    pub fn new() -> Arc<Self> {
        Arc::new(Self {
            inner: FileSystemTypeInner::new(String::from("tmpfs")),
            mounts: Mutex::new(BTreeMap::new()),
        })
    }
}

impl FileSystemType for TmpFsType {
    fn get_inner(&self)->&FileSystemTypeInner{
        &self.inner
    }

    fn mount(self:Arc<Self>,
            name:&str,
            parent:Option<Arc<dyn Dentry>>,
            flags: MountFlags,
            device:Option<Arc<dyn BlockDevice>>)->system_result::SysResult<Arc<dyn Dentry>> {
        let superblock = TmpSuperBlock::new(device, self.clone());
        superblock.set_read_only(flags.contains(MountFlags::MS_RDONLY));
        let mut stored_flags = MountFlags::from_bits_truncate(flags.bits());
        stored_flags.remove(MountFlags::MS_REMOUNT);
        superblock.set_mount_flags(stored_flags);
        let root_dentry = MemDentry::new(name, superblock.clone(), parent.clone());
        let root_inode = MemInode::new(InodeMode::DIR | InodeMode::all_perm(),  superblock.clone(),0,0);
        root_dentry.set_inode(root_inode);
        *root_dentry.get_state() = DentryState::Valid;
        if let Some(parent) = parent{
            let shadowed = parent.add_child(root_dentry.clone());
            self.mounts.lock().insert(
                root_dentry.path(),
                TmpMountInfo {
                    parent,
                    name: String::from(name),
                    shadowed,
                },
            );
        }
        self.add_superblock(root_dentry.path().as_str(), superblock);
        Ok(root_dentry)
    }
    fn umount(self:Arc<Self>,
            path:&str,
            _flags:MountFlags
        )->system_result::SysResult<()> {
        let info = self.mounts.lock().remove(path);
        if let Some(info) = info {
            match info.shadowed {
                // Restore the directory that this mount point shadowed.
                Some(shadowed) => { info.parent.add_child(shadowed); }
                // Nothing was shadowed: drop the synthetic mount root.
                None => { info.parent.remove_child(&info.name); }
            }
            let _ = self.remove_superblock(path);
            Ok(())
        } else {
            Err(SysError::EINVAL)
        }
    }

}

