pub struct ShmidKernel {
    num_pages: usize,
}

impl ShmidKernel {
    pub fn new(num: usize) -> Self {
        Self { num_pages: num }
    }
}

bitflags! {
    pub struct KernIpcPerm: i32 {
        const SHM_R = 0o400;
        const SHM_W = 0o200;
        const IPC_CREAT = 0o1000;
        const IPC_EXCL = 0o2000;
        const SHM_RDONLY = 0o10000;
        const SHM_EXEC   = 0o100000;
    }
}

lazy_static! {
    pub static ref IPCIDS: Mutex<IpcIds> = Mutex::new(IpcIds::new());
}

pub struct IpcIds {
    seq_max: usize,
    map: BTreeMap<usize, ShmidKernel>,
}

impl IpcIds {
    pub fn new() -> Self {
        Self {
            seq_max: 1,
            map: BTreeMap::new(),
        }
    }

    pub fn shm_get(&mut self, size: usize) -> usize {
        let num = (size + PAGE_SIZE - 1) / PAGE_SIZE;
        self.map.insert(self.seq_max, ShmidKernel::new(num));
        let ret = self.seq_max;
        self.seq_max += 1;
        ret
    }

    pub fn shm_exists(&self, key: usize) -> bool {
        self.map.get(&key).is_some()
    }

    pub fn shm_ctl(&mut self, key: usize) {
        self.map.remove(&key);
    }
}

pub fn shm_get(size: usize) -> usize {
    IPCIDS.lock().shm_get(size)
}

pub fn shm_exists(key: usize) -> bool {
    IPCIDS.lock().shm_exists(key)
}

pub fn shm_ctl(key: usize) {
    IPCIDS.lock().shm_ctl(key);
}

pub fn shm_num_pages(key: usize) -> Option<usize> {
    IPCIDS.lock().map.get(&key).map(|shm| shm.num_pages)
}

