#[derive(Debug, Clone, Copy, PartialEq, Default)]
#[repr(C)]
/// Describes times in seconds and microseconds.
pub struct TimeSpec {
    /// second
    pub sec: isize,
    /// microsecond
    pub nsec: isize,//actually should be ns
}

impl TimeSpec{
    pub fn new(sec:isize,nsec:isize)->Self{
        Self{
            sec,nsec
        }
    }
    pub fn to_nsec(&self)->isize{//actually should be to nsec
        self.sec*1000_000_000+self.nsec
    }
}

#[repr(C)]
#[derive(Debug, Clone, Copy, PartialEq,Default)]
///
pub struct TimeVal {
    ///
    pub sec: isize,  //秒
    ///
    pub usec: isize, //微秒
}

impl TimeVal{
    pub fn new(sec:isize,usec:isize)->Self{
        Self{
            sec,usec
        }
    }
    pub fn to_usec(&self)->isize{//
        self.sec*1000_000+self.usec
    }
    pub fn is_zero(&self)->bool{
        self.sec == 0 && self.usec == 0
    }
}

impl PartialOrd for TimeVal {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        if self.sec > other.sec {
            Some(Ordering::Greater)
        } else if self.sec < other.sec {
            Some(Ordering::Less)
        } else {
            if self.usec > other.usec {
                Some(Ordering::Greater)
            } else if self.usec < other.usec {
                Some(Ordering::Less)
            } else {
                Some(Ordering::Equal)
            }
        }
    }
}

impl PartialOrd for TimeSpec {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        if self.sec > other.sec {
            Some(Ordering::Greater)
        } else if self.sec < other.sec {
            Some(Ordering::Less)
        } else {
            if self.nsec > other.nsec {
                Some(Ordering::Greater)
            } else if self.nsec < other.nsec {
                Some(Ordering::Less)
            } else {
                Some(Ordering::Equal)
            }
        }
    }
}

impl Add for TimeVal {
    type Output = TimeVal;

    fn add(self, rhs: Self) -> Self::Output {
        let total_usec = self.usec + rhs.usec;
        Self {
            sec: self.sec + rhs.sec + total_usec / 1_000_000,
            usec: total_usec % 1_000_000,
        }
    }
}




