#[repr(C)]
///
pub struct TCBTms { //记录起始时间
    /// 用户时间
    pub tms_utime: isize,
    /// 系统时间
    pub tms_stime: isize,
    /// 子进程用户时间
    pub tms_cutime: isize, 
    /// 子进程系统时间
    pub tms_cstime: isize, 
    ///
    pub tcb_lasttime:isize,
}

impl TCBTms {
    pub fn new() -> Self {
        let now = get_curtime_ms() as isize;
        Self {
            tms_utime: 0,
            tms_stime: 0,
            tms_cutime: 0,
            tms_cstime: 0,
            tcb_lasttime: now,
        }
    }
    pub fn update_utime(&mut self) {
        let now = get_curtime_ms() as isize;
        let duration = now - self.tcb_lasttime;
        self.tms_utime += duration;
        self.tcb_lasttime = now;
    }
    pub fn update_stime(&mut self) {
        let now = get_curtime_ms() as isize;
        let duration = now - self.tcb_lasttime;
        self.tms_stime += duration;
        self.tcb_lasttime = now;
    }
    pub fn clear(&mut self) {
        let now = get_curtime_ms() as isize;
        self.tms_utime = 0;
        self.tms_stime = 0;
        self.tms_cutime = 0;
        self.tms_cstime = 0;
        self.tcb_lasttime = now;
    }
}


pub fn get_curtime_spec() -> TimeSpec {
    let curtime = Time::now().to_msec();
    TimeSpec::new((curtime / 1000) as isize, ((curtime % 1000) * 1000000) as isize) 
}

pub fn get_curtime_val() -> TimeVal {
    let curtime = Time::now().to_msec();
    TimeVal::new((curtime / 1000) as isize, ((curtime % 1000) * 1000) as isize)
}

pub fn get_curtime_ms() -> usize {
    Time::now().to_msec()
}

