//! Page fault handling policy framework.
//!
//! Policy-first design:
//! - Decide *what to do* based on VMA + access + fault cause.
//! - Execute actions later via page-table/frame backends.

use arch::PAGE_SIZE;
use system_result::{SysError, SysResult};

use super::types::{AccessType, FaultCause};
use super::vma_manager::{VmaBackend, VmaManager, VmaPerm, VmaRecord};

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum FaultAction {
    AllocAnonPage,
    LoadFilePage { inode_id: usize, offset: usize },
    LoadElfPage {
        inode_id: usize,
        file_offset: usize,
        file_bytes: usize,
    },
    MapSharedPage { inode_id: usize, offset: usize },
    DoCow,
}

pub struct FaultHandler<'a> {
    pub vma_mgr: &'a mut VmaManager,
}

impl<'a> FaultHandler<'a> {
    pub fn new(vma_mgr: &'a mut VmaManager) -> Self {
        Self { vma_mgr }
    }

    /// Top-level dispatch for fault policy.
    pub fn handle_fault(&mut self, addr: usize, access: AccessType, cause: FaultCause) -> SysResult<FaultAction> {
        match cause {
            FaultCause::Lazy => self.handle_lazy_fault(addr, access),
            FaultCause::Cow => self.handle_cow_fault(addr, access),
        }
    }

    /// Lazy fault policy: locate VMA, check access permission, then return action.
    pub fn handle_lazy_fault(&mut self, addr: usize, access: AccessType) -> SysResult<FaultAction> {
        let area = self.vma_mgr.find(addr).ok_or(SysError::EADDRNOTAVAIL)?;
        self.check_access_perm(area, access)?;
        self.decide_lazy_action(area, addr)
    }

    /// COW fault policy: requires writable VMA semantics and write access.
    pub fn handle_cow_fault(&mut self, addr: usize, access: AccessType) -> SysResult<FaultAction> {
        let area = self.vma_mgr.find(addr).ok_or(SysError::EADDRNOTAVAIL)?;
        if access != AccessType::Write {
            return Err(SysError::EFAULT);
        }
        if !area.perm.contains(VmaPerm::W) || !area.perm.contains(VmaPerm::COW) {
            return Err(SysError::EFAULT);
        }
        Ok(FaultAction::DoCow)
    }

    fn check_access_perm(&self, area: &VmaRecord, access: AccessType) -> SysResult<()> {
        let allowed = match access {
            AccessType::Read => area.perm.contains(VmaPerm::R),
            AccessType::Write => area.perm.contains(VmaPerm::W),
            AccessType::Execute => area.perm.contains(VmaPerm::X),
        };
        if allowed {
            Ok(())
        } else {
            Err(SysError::EFAULT)
        }
    }

    /// Map a lazily-faulted VMA + faulting (page-aligned) address to the page
    /// backend action. Physical (device) mappings are never lazily faulted.
    fn decide_lazy_action(&self, area: &VmaRecord, addr: usize) -> SysResult<FaultAction> {
        match area.backend {
            VmaBackend::Anonymous => Ok(FaultAction::AllocAnonPage),
            VmaBackend::Physical { .. } => Err(SysError::ENOSYS),

