}

impl VmaRange {
    /// Returns the length in bytes. Range is half-open `[start, end)`.
    pub fn len(&self) -> usize {
        self.end - self.start
    }

    pub fn contains(&self, addr: usize) -> bool {
        addr >= self.start && addr < self.end
