//! SBI console driver, for text output
use arch::console_putchar;
use core::fmt::{self, Write};
use spin::Mutex;
//use crate::drivers::chardevice::{CharDevice, UART};

struct Stdout;

// Keep CR/LF state across write_str calls so split "\r" + "\n" chunks
// are not expanded to "\r\r\n".
static LAST_WAS_CR: Mutex<bool> = Mutex::new(false);

impl Write for Stdout {
    fn write_str(&mut self, s: &str) -> fmt::Result {
        let mut prev_was_cr = LAST_WAS_CR.lock();
        for c in s.bytes() {
            match c {
                b'\n' => {
                    #[cfg(target_arch = "loongarch64")]
                    if !*prev_was_cr {
                        console_putchar(b'\r');
                    }
                    console_putchar(b'\n');
                    *prev_was_cr = false;
                }
                b'\r' => {
                    console_putchar(b'\r');
                    *prev_was_cr = true;
                }
                _ => {
                    console_putchar(c);
                    *prev_was_cr = false;
                }
            }
        }
        Ok(())
    }
}

pub fn print(args: fmt::Arguments) {
    Stdout.write_fmt(args).unwrap();
}

#[macro_export]
/// print string macro
macro_rules! print {
    ($fmt: literal $(, $($arg: tt)+)?) => {
        $crate::console::print(format_args!($fmt $(, $($arg)+)?))
    }
}

#[macro_export]
/// println string macro
macro_rules! println {
    ($fmt: literal $(, $($arg: tt)+)?) => {{
        $crate::console::print(format_args!(concat!($fmt, "\n") $(, $($arg)+)?))
    }};
}

/// Master switch for verbose per-syscall trace prints (`[sys_exec]`,
/// `[wait-trace]`, …). Off by default so the test-suite output stays clean;
/// set to `true` when debugging exec/fork/wait/reap behavior. When `false` the
/// `debug_trace!` body is `if false { … }`, which the compiler eliminates, so
/// there is no runtime cost.
pub const DEBUG_TRACE: bool = false;

/// Low-noise switch for process-death diagnostics. Unlike [`DEBUG_TRACE`] this
/// is meant to stay *on* during real test runs: it only prints when a process
/// is killed by a fatal signal (SIGSEGV/SIGBUS/SIGILL/SIGABRT/…), which is rare,
/// so it does not flood lmbench output. Each `[crash]` line carries the user PC
/// (faulting instruction) so an intermittent segfault can be pinned to an
/// address even when `[pgfault-kill]` does not fire (e.g. the crash came in via
/// a SIGSEGV handler that re-faulted, or from a non-page-fault source).
pub const CRASH_TRACE: bool = true;

#[macro_export]
/// println that only fires when [`crate::console::DEBUG_TRACE`] is enabled.
macro_rules! debug_trace {
    ($fmt: literal $(, $($arg: tt)+)?) => {
        if $crate::console::DEBUG_TRACE {
            $crate::console::print(format_args!(concat!($fmt, "\n") $(, $($arg)+)?));
        }
    }
}
