//! Architecture-neutral page table driver built on the `arch::pagetable`
//! abstraction, so the same code drives whichever target arch is selected.

use arch::addr::{PhysAddr, PhysPageNum, VirtAddr, VirtPageNum};
use arch::pagetable::{MappingFlags, MappingSize, PageTable, TLB};
use arch::PAGE_SIZE;
use system_result::{SysError, SysResult};

use super::PageTableDriver;

#[derive(Default)]
pub struct ArchPageTableDriver {
    page_table: Option<PageTable>,
}

impl ArchPageTableDriver {
    pub fn new() -> Self {
        Self { page_table: None }
    }

    pub fn bind_page_table(&mut self, page_table: PageTable) {
        self.page_table = Some(page_table);
    }

    fn page_table(&self) -> SysResult<&PageTable> {
        self.page_table.as_ref().ok_or(SysError::ENODEV)
    }
}

impl PageTableDriver for ArchPageTableDriver {
    fn map(&mut self, va: usize, pa: usize, perm_bits: usize) -> SysResult<()> {
        if va % PAGE_SIZE != 0 || pa % PAGE_SIZE != 0 {
            return Err(SysError::EINVAL);
        }
        let pt = self.page_table()?;
        let mut flags = MappingFlags::from_bits_truncate(perm_bits as u64);
        flags |= MappingFlags::P;
        pt.map_page(
            VirtPageNum::from(VirtAddr::from(va)),
            PhysPageNum::from(PhysAddr::new(pa)),
            flags,
            MappingSize::Page4KB,
        );
        Ok(())
    }

    fn unmap(&mut self, va: usize) -> SysResult<()> {
        if va % PAGE_SIZE != 0 {
            return Err(SysError::EINVAL);
        }
        let pt = self.page_table()?;
        pt.unmap_page(VirtPageNum::from(VirtAddr::from(va)));
        Ok(())
    }

    fn protect(&mut self, va: usize, perm_bits: usize) -> SysResult<()> {
        if va % PAGE_SIZE != 0 {
            return Err(SysError::EINVAL);
        }
        let pt = self.page_table()?;
        let va_obj = VirtAddr::from(va);
        let (pa, old_flags) = pt.translate(va_obj).ok_or(SysError::EADDRNOTAVAIL)?;
        let mut flags = MappingFlags::from_bits_truncate(perm_bits as u64);
        let keep_flags = old_flags & (MappingFlags::A | MappingFlags::D | MappingFlags::G | MappingFlags::cow);
        flags |= keep_flags | MappingFlags::P;
        pt.map_page(
            VirtPageNum::from(va_obj),
            PhysPageNum::from(pa),
            flags,
            MappingSize::Page4KB,
        );
        Ok(())
    }

    fn query(&self, va: usize) -> Option<usize> {
        let pt = self.page_table().ok()?;
        pt.translate(VirtAddr::from(va)).map(|(pa, _flags)| pa.addr())
    }

    fn flush_tlb(&self, va: Option<usize>) {
        match va {
            Some(v) => TLB::flush_vaddr(VirtAddr::from(v)),
            None => TLB::flush_all(),
        }
    }

    fn activate(&self) {
        if let Ok(pt) = self.page_table() {
            pt.change();
        }
    }
}

