pub fn sys_get_time(ts: *mut TimeVal, tz: usize) -> SysResult<isize> {
    if ts as usize >= VIRT_ADDR_START || tz >= VIRT_ADDR_START {
        return Err(SysError::EFAULT);
    }
    let current_task = current_task().unwrap();
    let inner = current_task.inner_exclusive_access();
    if ts.is_null() {
        return Err(SysError::EINVAL);
    }
    let ts = user_translated_refmut(&inner,ts)?;
    let curtime = get_curtime_val();
    *ts = curtime;
    Ok(0)
}
